/// Example hook.
pub const EXAMPLE_HOOK: &str = r#"# Copyright (c) 2026 SPHARX Ltd. All Rights Reserved.
"""
Custom Hook for AgentRT

Hooks intercept agent lifecycle events.
This example logs all tool calls to the console.
"""

from ecosystem.hooks import BaseHook, HookContext, HookResult


class CustomAuditHook(BaseHook):
    name = "custom_audit"
    version = "0.1.0"
    priority = 50

    def on_tool_call(self, ctx: HookContext, tool_name: str = "", tool_input: Any = None) -> HookResult:
        print(f"[HOOK] Tool called: {tool_name} by agent {ctx.agent_id}")
        return HookResult(allowed=True)

    def on_tool_result(self, ctx: HookContext, tool_name: str = "", result: Any = None) -> HookResult:
        print(f"[HOOK] Tool result: {tool_name} -> {str(result)[:100]}")
        return HookResult(allowed=True)
"#;

/// Example plugin.
pub const EXAMPLE_PLUGIN: &str = r#"# Copyright (c) 2026 SPHARX Ltd. All Rights Reserved.
"""
Example Plugin for AgentRT

Plugins extend the AgentRT runtime with custom functionality.
They follow a lifecycle: init -> start -> stop -> destroy.
"""

from typing import Any, Dict


class MyPlugin:
    """Example plugin implementation."""

    def __init__(self):
        self._running = False

    def init(self, config: Dict[str, Any]) -> bool:
        """Initialize the plugin with configuration."""
        print(f"[PLUGIN] Initializing with config: {config}")
        return True

    def start(self) -> bool:
        """Start the plugin."""
        self._running = True
        print("[PLUGIN] Started")
        return True

    def stop(self) -> bool:
        """Stop the plugin."""
        self._running = False
        print("[PLUGIN] Stopped")
        return True

    def destroy(self) -> bool:
        """Clean up plugin resources."""
        print("[PLUGIN] Destroyed")
        return True

    def is_running(self) -> bool:
        """Check if the plugin is running."""
        return self._running
"#;

